from collections import defaultdict

class EventEmitter:
    def __init__(self):
        # Stores {event_name: set_of_listeners}
        # Using None as a placeholder for temporary storage/structure simplification
        self._listeners = defaultdict(list)
        # Stores event names with single-use listeners (track list index to manage 'once' removal safely)
        self._once_listeners = defaultdict(list)
        self._next_index = 0

    def on(self, event: str, listener):
        """Registers a permanent listener."""
        # Store the listener and a unique identifier for potential removal later
        self._listeners[event].append(listener)

    def off(self, event: str, listener):
        """Removes a specific listener for an event."""
        if event in self._listeners:
            try:
                self._listeners[event].remove(listener)
            except ValueError:
                # Listener was not registered
                pass

    def once(self, event: str, listener):
        """Registers a single-use listener. It is automatically removed after being called once."""
        self._once_listeners[event].append({'listener': listener})

    def emit(self, event: str, *args):
        """Emits an event, calling all registered listeners with the given arguments."""
        # 1. Handle standard listeners (Permanent and Once)
        if event in self._listeners:
            listeners_to_call = list(self._listeners[event])
            for listener in listeners_to_call:
                try:
                    listener(*args)
                except Exception as e:
                    print(f"Error calling listener for {event}: {e}")

        # 2. Handle 'once' listeners (Iterate over a copy because we might modify the list)
        if event in self._once_listeners:
            once_list = self._once_listeners[event]
            listeners_to_call = list(once_list) # Safe copy for iteration

            for item in listeners_to_call:
                listener = item['listener']
                try:
                    listener(*args)
                    # If calling succeeds, remove it immediately from the 'once' tracking mechanism
                    self._once_listeners[event].remove(item)
                except Exception as e:
                    print(f"Error calling once listener for {event}: {e}")

        # Cleanup empty lists (optional but good practice)
        if not self._listeners.get(event):
            del self._listeners[event]
        if not self._once_listeners.get(event):
            del self._once_listeners[event]

